import React, { useState } from "react";
import axios from "axios";
import "./assets/contactStyle.css";
const MailSenderApi = "http://techboyraju.com:5000/"

const CreatePostForm = () => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [message, setMessage] = useState("");
  const [statusMessage, setStatusMessage] = useState("");
  const handleNameChange = (e) => {
    setName(e.target.value);
  };
  const handleEmailChange = (e) => {
    setEmail(e.target.value);
  };
  const handleMessageChange = (e) => {
    setMessage(e.target.value);
  };
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post(
        MailSenderApi,
        { name, email, message }
      );
      setStatusMessage("Message sent successfully!");
      setName("");
      setEmail("");
      setMessage("");
      setTimeout(() => {
        setStatusMessage("");
      }, 2500);
    } catch (error) {
      setStatusMessage(
        <p style={{ color: "red" }}>
          Failed to send message. Please try again later.
        </p>
      );
    }
  };

  return (
    <div name="contact" id="contacts" className="contact section">
      <div className="flex flex-col p-4 justify-center max-w-screen-lg mx-auto h-full myContact">
        <div className="max-w-screen-lg mx-auto p-4 flex flex-col justify-center  text-white">
          <p className="text-4xl font-bold border-b-4 border-gray-500 p-2 inline">
            Contact
          </p>
        </div>

        <div className="flex justify-center items-center">
          <form
            // onSubmit={handleSubmit}
            method="post"
            action="https://formspree.io/f/mdovpqeo"
            className=" flex flex-col w-full md:w-1/2"
          >
            <input
              type="text"
              value={name}
              onChange={handleNameChange}
              name="name"
              placeholder="Enter your name"
              className="p-2 bg-transparent border-2 rounded-md text-white focus:outline-none"
              required
            />
            <input
              type="email"
              value={email}
              onChange={handleEmailChange}
              name="email"
              placeholder="Enter your email"
              className="my-4 p-2 bg-transparent border-2 rounded-md text-white focus:outline-none"
              required
            />
            <textarea
              name="message"
              value={message}
              onChange={handleMessageChange}
              placeholder="Enter your message"
              rows="10"
              className="p-2 bg-transparent border-2 rounded-md text-white focus:outline-none"
              required
            ></textarea>
            <button className="text-white bg-gradient-to-b from-cyan-500 to-blue-500 px-6 py-3 my-8 mx-auto flex items-center rounded-md hover:scale-110 duration-300">
              Let's talk
            </button>
            {statusMessage && (
              <div className="text-center text-white my-4">{statusMessage}</div>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default CreatePostForm;
